"""ctxcli - Context Surfaces Agent User CLI.

Main application entry point with dynamic command generation.
"""

import os
import sys
from typing import Annotated

import typer
from rich.console import Console

from context_surfaces.cli.ctxcli.commands.init import init_command
from context_surfaces.cli.ctxcli.commands.tools import tools_app
from context_surfaces.cli.ctxcli.config import ConfigManager
from context_surfaces.cli.ctxcli.constants import DEFAULT_PROFILE_NAME, ENV_PROFILE

console = Console()


def _get_profile_from_argv() -> str | None:
    """Pre-parse --profile/-p argument from sys.argv.

    This is needed because dynamic entity commands are registered at module load time,
    before Typer parses arguments. We need to know the profile early to load the
    correct tools for that profile.

    Returns:
        Profile name from CLI args, or None if not specified.
    """
    args = sys.argv[1:]  # Skip the program name
    i = 0
    while i < len(args):
        arg = args[i]
        # Handle --profile=value or -p=value
        if arg.startswith("--profile="):
            return arg.split("=", 1)[1]
        if arg.startswith("-p="):
            return arg.split("=", 1)[1]
        # Handle --profile value or -p value
        if arg in ("--profile", "-p") and i + 1 < len(args) and not args[i + 1].startswith("-"):
            return args[i + 1]
        i += 1
    return None


def _create_app() -> typer.Typer:
    """Create the main Typer app with dynamic entity commands."""
    main_app = typer.Typer(
        name="ctxcli",
        help="Context Surfaces Agent CLI - Interact with MCP tools using natural commands",
        add_completion=True,
        rich_markup_mode="rich",
        no_args_is_help=False,
        invoke_without_command=True,
    )

    # Register static commands
    main_app.command("init")(init_command)
    main_app.add_typer(tools_app)

    # Register dynamic entity commands if profile is initialized
    _register_entity_commands(main_app)

    return main_app


def _register_entity_commands(main_app: typer.Typer) -> None:
    """Register dynamic entity commands from cached tools.

    Profile is determined by checking (in order):
    1. --profile/-p CLI argument (pre-parsed from sys.argv)
    2. CTXCLI_PROFILE environment variable
    3. Default profile name ('default')
    """
    # Pre-parse --profile from CLI args before Typer processes them
    profile_name = _get_profile_from_argv()
    if profile_name is None:
        profile_name = os.environ.get(ENV_PROFILE, DEFAULT_PROFILE_NAME)

    try:
        config_manager = ConfigManager()
        if not config_manager.is_initialized(profile_name):
            return

        profile = config_manager.get_profile(profile_name)
        if not profile.tools_cache or not profile.tools_cache.tools:
            return

        from context_surfaces.cli.ctxcli.dynamic import create_entity_app
        from context_surfaces.cli.ctxcli.transformer import (
            group_commands_by_entity,
            transform_tool_name,
        )

        # Transform tools to commands
        commands = [
            transform_tool_name(
                tool.name,
                tool.description,
                tool.input_schema,
            )
            for tool in profile.tools_cache.tools
        ]

        # Group by entity and register
        grouped = group_commands_by_entity(commands)
        for entity, cmds in grouped.items():
            entity_app = create_entity_app(entity, cmds, config_manager, profile_name)
            main_app.add_typer(entity_app, name=entity)

    except Exception:
        # Silently ignore errors during command registration
        # This allows the CLI to still work with init/tools commands
        pass


# Create the app at module load time
app = _create_app()


def _get_profile_name() -> str:
    """Get the active profile name from env or default."""
    return os.environ.get(ENV_PROFILE, DEFAULT_PROFILE_NAME)


def _show_init_help() -> None:
    """Show help text for uninitialized state."""
    console.print("\n[bold]Context Surfaces Agent CLI[/bold]\n")
    console.print("No profile configured. To get started, run:\n")
    console.print("  [cyan]ctxcli init[/cyan]\n")
    console.print("This will prompt for your agent key and configure the CLI.\n")
    console.print("Options:")
    console.print("  [dim]--agent-key[/dim]    Agent key (or set CTXCLI_AGENT_KEY)")
    console.print("  [dim]--mcp-url[/dim]      MCP server URL (optional)")
    console.print("  [dim]--profile[/dim]      Profile name (default: 'default')")


def _show_full_help(config_manager: ConfigManager, profile_name: str) -> None:
    """Show full help with available entity commands."""
    from context_surfaces.cli.ctxcli.transformer import (
        group_commands_by_entity,
        transform_tool_name,
    )

    profile = config_manager.get_profile(profile_name)

    console.print("\n[bold]Context Surfaces Agent CLI[/bold]\n")
    console.print(f"Profile: [cyan]{profile_name}[/cyan]\n")

    console.print("[bold]Commands:[/bold]")
    console.print("  [cyan]init[/cyan]              Initialize CLI with agent key")
    console.print("  [cyan]tools refresh[/cyan]    Force refresh tools cache")
    console.print("  [cyan]tools raw[/cyan]        Call tool by original MCP name\n")

    if profile.tools_cache and profile.tools_cache.tools:
        # Transform and group tools
        commands = [
            transform_tool_name(
                tool.name,
                tool.description,
                tool.input_schema,
            )
            for tool in profile.tools_cache.tools
        ]
        grouped = group_commands_by_entity(commands)

        console.print("[bold]Entities:[/bold]")
        for entity, cmds in sorted(grouped.items()):
            console.print(f"  [bold cyan]{entity}[/bold cyan]:")
            for cmd in cmds:
                # Build command signature
                positional = cmd.get_positional_args()
                flags = cmd.get_flag_args()

                args_str = " ".join(f"<{arg}>" for arg in positional)
                if cmd.filter_field:
                    args_str = f"--by={cmd.filter_field} --value=<value>"
                elif cmd.verb == "search":
                    args_str = "--search-term=<text>"
                elif flags:
                    optional_flags = [f"--{k}=<{v['type']}>" for k, v in flags.items() if not v["required"]]
                    if optional_flags:
                        args_str += " " + " ".join(f"[{f}]" for f in optional_flags[:2])

                console.print(f"    {cmd.verb} {args_str}")

        console.print()

    console.print("[bold]Options:[/bold]")
    console.print("  [dim]--profile[/dim]      Profile to use")
    console.print("  [dim]--output[/dim]       Output format: table, json, yaml")
    console.print("  [dim]-v, --verbose[/dim]  Show connection context")
    console.print("  [dim]--help[/dim]         Show this help")


@app.callback(invoke_without_command=True)
def main_callback(
    ctx: typer.Context,
    profile: Annotated[
        str | None,
        typer.Option(
            "--profile",
            "-p",
            help="Profile to use",
            envvar=ENV_PROFILE,
        ),
    ] = None,
    verbose: Annotated[
        bool,
        typer.Option(
            "--verbose",
            "-v",
            help="Show connection context",
        ),
    ] = False,
) -> None:
    """Context Surfaces Agent CLI.

    If not initialized, shows help for initialization.
    If initialized, shows available entity commands.
    """
    # Store options in context for subcommands
    ctx.ensure_object(dict)
    ctx.obj["profile"] = profile or _get_profile_name()
    ctx.obj["verbose"] = verbose
    ctx.obj["config_manager"] = ConfigManager()

    # If a subcommand is being invoked, let it handle things
    if ctx.invoked_subcommand is not None:
        return

    # No subcommand: show appropriate help
    config_manager: ConfigManager = ctx.obj["config_manager"]
    profile_name: str = ctx.obj["profile"]

    if not config_manager.is_initialized(profile_name):
        _show_init_help()
    else:
        _show_full_help(config_manager, profile_name)


def cli_main() -> None:
    """Entry point for the ctxcli CLI."""
    app()

